def calculate_gender_balance(ministry_data):
    total = ministry_data['total_members']
    women = ministry_data['women']
    men = ministry_data['men']
    balance_percentage = (women / total) * 100
    return {
        'total_members': total,
        'women': women,
        'men': men,
        'women_percentage': balance_percentage
    }

# Example usage:
ministry_data = {'total_members': 35, 'women': 17, 'men': 18}
print(calculate_gender_balance(ministry_data))
# Output: {'total_members': 35, 'women': 17, 'men': 18, 'women_percentage': 48.57142857142857}
